#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005

int maxCost = 0;

void dfs(int node, int parent, int *cost, int **adj, int *visited, int N) {
    visited[node] = 1;
    int subsetSize = 1;
    int and = node;
    for (int i = 0; i < adj[node][0]; i++) {
        int child = adj[node][i + 1];
        if (child != parent && !visited[child]) {
            dfs(child, node, cost, adj, visited, N);
            subsetSize++;
            and &= child;
        }
    }
    cost[node] = subsetSize * and;
    maxCost = (maxCost > cost[node]) ? maxCost : cost[node];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int **adj = (int **)malloc(N * sizeof(int *));
        int *cost = (int *)malloc(N * sizeof(int));
        int *visited = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            adj[i] = (int *)malloc(2 * sizeof(int));
            adj[i][0] = 0;
        }
        for (int i = 0; i < N - 1; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            x--;
            y--;
            adj[x][0]++;
            adj[x] = (int *)realloc(adj[x], (adj[x][0] + 1) * sizeof(int));
            adj[x][adj[x][0]] = y;
            adj[y][0]++;
            adj[y] = (int *)realloc(adj[y], (adj[y][0] + 1) * sizeof(int));
            adj[y][adj[y][0]] = x;
        }
        maxCost = 0;
        dfs(0, -1, cost, adj, visited, N);
        printf("%d\n", maxCost);
        for (int i = 0; i < N; i++) {
            free(adj[i]);
        }
        free(adj);
        free(cost);
        free(visited);
    }
    return 0;
}

