import java.util.Scanner;
import java.util.ArrayList;

public class Main {
    static int maxCost = 0;

    public static void dfs(int node, int parent, ArrayList<Integer>[] adj, int[] cost, boolean[] visited, int N) {
        visited[node] = true;
        int subsetSize = 1;
        int and = node + 1;
        for (int i = 0; i < adj[node].size(); i++) {
            int child = adj[node].get(i);
            if (child != parent && !visited[child]) {
                dfs(child, node, adj, cost, visited, N);
                subsetSize++;
                and &= (child + 1);
            }
        }
        cost[node] = subsetSize * and;
        maxCost = (maxCost > cost[node]) ? maxCost : cost[node];
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            ArrayList<Integer>[] adj = new ArrayList[N];
            int[] cost = new int[N];
            boolean[] visited = new boolean[N];
            for (int i = 0; i < N; i++) {
                adj[i] = new ArrayList<>();
                visited[i] = false;
            }
            for (int i = 0; i < N - 1; i++) {
                int x = scanner.nextInt() - 1;
                int y = scanner.nextInt() - 1;
